import React, { useState } from 'react';
import axios from 'axios';
import { Upload, Wand2, Download, Loader2 } from 'lucide-react';
import { Button } from './ui/button';
import { Card } from './ui/card';

const StyleGenerator = () => {
  const [selectedFile, setSelectedFile] = useState(null);
  const [previewUrl, setPreviewUrl] = useState(null);
  const [selectedStyle, setSelectedStyle] = useState('科幻风');
  const [isGenerating, setIsGenerating] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const styles = [
    '科幻风',
    '古风',
    '卡通风格',
    '水彩画风格',
    '油画风格',
    '像素艺术风格',
    '赛博朋克风格',
    '日式动漫风格'
  ];

  const handleFileSelect = (e) => {
    const file = e.target.files[0];
    if (file) {
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
      setResult(null);
      setError(null);
    }
  };

  const handleGenerate = async () => {
    if (!selectedFile) {
      setError('请先选择一张课表图片');
      return;
    }

    setIsGenerating(true);
    setError(null);

    const formData = new FormData();
    formData.append('image', selectedFile);
    formData.append('style', selectedStyle);

    try {
      const response = await axios.post('/api/generate-style', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      setResult(response.data);
    } catch (err) {
      console.error('生成失败:', err);
      setError(err.response?.data?.error || '生成失败，请重试');
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (result?.styledImage) {
      const link = document.createElement('a');
      link.href = result.styledImage;
      link.download = `styled-schedule-${Date.now()}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  return (
    <div className="style-generator">
      <Card className="p-6">
        <h2 className="text-2xl font-bold mb-6">课表风格生成器</h2>

        <div className="space-y-6">
          {/* 上传区域 */}
          <div>
            <label className="block text-sm font-medium mb-2">上传课表图片</label>
            <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center hover:border-gray-400 transition-colors">
              <input
                type="file"
                id="image-upload"
                accept="image/*"
                onChange={handleFileSelect}
                className="hidden"
              />
              <label
                htmlFor="image-upload"
                className="cursor-pointer flex flex-col items-center"
              >
                <Upload className="w-12 h-12 text-gray-400 mb-2" />
                <span className="text-sm text-gray-600">
                  点击上传或拖拽图片到此处
                </span>
              </label>
            </div>
          </div>

          {/* 预览区域 */}
          {previewUrl && (
            <div>
              <label className="block text-sm font-medium mb-2">原始图片</label>
              <img
                src={previewUrl}
                alt="预览"
                className="max-w-full h-auto rounded-lg border"
              />
            </div>
          )}

          {/* 风格选择 */}
          <div>
            <label className="block text-sm font-medium mb-2">选择风格</label>
            <select
              value={selectedStyle}
              onChange={(e) => setSelectedStyle(e.target.value)}
              className="w-full p-2 border rounded-lg"
            >
              {styles.map((style) => (
                <option key={style} value={style}>
                  {style}
                </option>
              ))}
            </select>
          </div>

          {/* 生成按钮 */}
          <Button
            onClick={handleGenerate}
            disabled={!selectedFile || isGenerating}
            className="w-full"
          >
            {isGenerating ? (
              <>
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                生成中...
              </>
            ) : (
              <>
                <Wand2 className="w-4 h-4 mr-2" />
                生成风格化课表
              </>
            )}
          </Button>

          {/* 错误提示 */}
          {error && (
            <div className="text-red-500 text-sm bg-red-50 p-3 rounded-lg">
              {error}
            </div>
          )}

          {/* 结果展示 */}
          {result && (
            <div className="space-y-4">
              <h3 className="text-lg font-semibold">生成结果</h3>
              <img
                src={result.styledImage}
                alt="风格化结果"
                className="max-w-full h-auto rounded-lg border"
              />
              <Button onClick={handleDownload} className="w-full">
                <Download className="w-4 h-4 mr-2" />
                下载图片
              </Button>
            </div>
          )}
        </div>
      </Card>
    </div>
  );
};

export default StyleGenerator;
